    37→// unaryClientInterceptor returns a new retrying unary client interceptor.
    38→//
    39→// The default configuration of the interceptor is to not retry *at all*. This behaviour can be
    40→// changed through options (e.g. WithMax) on creation of the interceptor or on call (through grpc.CallOptions).
    41→func (c *Client) unaryClientInterceptor(optFuncs ...retryOption) grpc.UnaryClientInterceptor {
    42→	intOpts := reuseOrNewWithCallOptions(defaultOptions, optFuncs)
    43→	return func(ctx context.Context, method string, req, reply any, cc *grpc.ClientConn, invoker grpc.UnaryInvoker, opts ...grpc.CallOption) error {
    44→		ctx = withVersion(ctx)
    45→		grpcOpts, retryOpts := filterCallOptions(opts)
    46→		var p peer.Peer
    47→		grpcOpts = append(grpcOpts, grpc.Peer(&p))
    48→		callOpts := reuseOrNewWithCallOptions(intOpts, retryOpts)
    49→		// short circuit for simplicity, and avoiding allocations.
    50→		if callOpts.max == 0 {
    51→			return invoker(ctx, method, req, reply, cc, grpcOpts...)
    52→		}
    53→		var lastErr error
    54→		for attempt := uint(0); attempt < callOpts.max; attempt++ {
    55→			if err := waitRetryBackoff(ctx, attempt, callOpts); err != nil {
    56→				return err
    57→			}
    58→			c.GetLogger().Debug(
    59→				"retrying of unary invoker",
    60→				zap.String("target", cc.Target()),
    61→				zap.String("method", method),
    62→				zap.Uint("attempt", attempt),
    63→			)
    64→			lastErr = invoker(ctx, method, req, reply, cc, grpcOpts...)
    65→			if lastErr == nil {
    66→				return nil
    67→			}
    68→			c.GetLogger().Warn(
    69→				"retrying of unary invoker failed",
    70→				zap.String("target", cc.Target()),
    71→				zap.String("peer", p.String()),
    72→				zap.String("method", method),
    73→				zap.Uint("attempt", attempt),
    74→				zap.Error(lastErr),
    75→			)
    76→			if isContextError(lastErr) {
    77→				if ctx.Err() != nil {
    78→					// its the context deadline or cancellation.
    79→					return lastErr
    80→				}
    81→				// its the callCtx deadline or cancellation, in which case try again.
    82→				continue
    83→			}
    84→			if c.shouldRefreshToken(lastErr, callOpts) {
    85→				gtErr := c.refreshToken(ctx)
    86→				if gtErr != nil {
    87→					c.GetLogger().Warn(
    88→						"retrying of unary invoker failed to fetch new auth token",
    89→						zap.String("target", cc.Target()),
    90→						zap.Error(gtErr),
    91→					)
    92→					return gtErr // lastErr must be invalid auth token
    93→				}
    94→				continue
    95→			}
    96→			if !isSafeRetry(c, lastErr, callOpts) {
    97→				return lastErr
    98→			}
    99→		}
   100→		return lastErr
   101→	}
   102→}
   103→
   104→// streamClientInterceptor returns a new retrying stream client interceptor for server side streaming calls.
   105→//
   106→// The default configuration of the interceptor is to not retry *at all*. This behaviour can be
   107→// changed through options (e.g. WithMax) on creation of the interceptor or on call (through grpc.CallOptions).
   108→//
   109→// Retry logic is available *only for ServerStreams*, i.e. 1:n streams, as the internal logic needs
   110→// to buffer the messages sent by the client. If retry is enabled on any other streams (ClientStreams,
   111→// BidiStreams), the retry interceptor will fail the call.
   112→func (c *Client) streamClientInterceptor(optFuncs ...retryOption) grpc.StreamClientInterceptor {
   113→	intOpts := reuseOrNewWithCallOptions(defaultOptions, optFuncs)
   114→	return func(ctx context.Context, desc *grpc.StreamDesc, cc *grpc.ClientConn, method string, streamer grpc.Streamer, opts ...grpc.CallOption) (grpc.ClientStream, error) {
   115→		ctx = withVersion(ctx)
   116→		// getToken automatically. Otherwise, auth token may be invalid after watch reconnection because the token has expired
   117→		// (see https://github.com/etcd-io/etcd/issues/11954 for more).
   118→		err := c.getToken(ctx)
   119→		if err != nil {
   120→			c.GetLogger().Error("clientv3/retry_interceptor: getToken failed", zap.Error(err))
   121→			return nil, err
   122→		}
   123→		grpcOpts, retryOpts := filterCallOptions(opts)
   124→		callOpts := reuseOrNewWithCallOptions(intOpts, retryOpts)
   125→		// short circuit for simplicity, and avoiding allocations.
   126→		if callOpts.max == 0 {
   127→			return streamer(ctx, desc, cc, method, grpcOpts...)
   128→		}
   129→		if desc.ClientStreams {
   130→			return nil, status.Errorf(codes.Unimplemented, "clientv3/retry_interceptor: cannot retry on ClientStreams, set Disable()")
   131→		}
   132→		newStreamer, err := streamer(ctx, desc, cc, method, grpcOpts...)
   133→		if err != nil {
   134→			c.GetLogger().Error("streamer failed to create ClientStream", zap.Error(err))
   135→			return nil, err // TODO(mwitkow): Maybe dial and transport errors should be retriable?
   136→		}
   137→		retryingStreamer := &serverStreamingRetryingStream{
   138→			client:       c,
   139→			ClientStream: newStreamer,
   140→			callOpts:     callOpts,
   141→			ctx:          ctx,
   142→			streamerCall: func(ctx context.Context) (grpc.ClientStream, error) {
   143→				return streamer(ctx, desc, cc, method, grpcOpts...)
   144→			},
   145→		}
   146→		return retryingStreamer, nil
   147→	}
   148→}
   149→
   150→// shouldRefreshToken checks whether there's a need to refresh the token based on the error and callOptions,
   151→// and returns a boolean value.
   152→func (c *Client) shouldRefreshToken(err error, callOpts *options) bool {
   153→	if c.Token != "" {
   154→		// do not try to refresh the token as it is set by user
   155→		return false
   156→	}
   157→
   158→	if errors.Is(rpctypes.Error(err), rpctypes.ErrUserEmpty) {
   159→		// refresh the token when username, password is present but the server returns ErrUserEmpty
   160→		// which is possible when the client token is cleared somehow
   161→		return c.authTokenBundle != nil // equal to c.Username != "" && c.Password != ""
   162→	}
   163→
   164→	return callOpts.retryAuth &&
   165→		(errors.Is(rpctypes.Error(err), rpctypes.ErrInvalidAuthToken) || errors.Is(rpctypes.Error(err), rpctypes.ErrAuthOldRevision))
   166→}
   167→
   168→func (c *Client) refreshToken(ctx context.Context) error {
   169→	if c.authTokenBundle == nil {
   170→		// c.authTokenBundle will be initialized only when
   171→		// c.Username != "" && c.Password != "".
   172→		//
   173→		// When users use the TLS CommonName based authentication, the
   174→		// authTokenBundle is always nil. But it's possible for the clients
   175→		// to get `rpctypes.ErrAuthOldRevision` response when the clients
   176→		// concurrently modify auth data (e.g, addUser, deleteUser etc.).
   177→		// In this case, there is no need to refresh the token; instead the
   178→		// clients just need to retry the operations (e.g. Put, Delete etc).
   179→		return nil
   180→	}
   181→
   182→	return c.getToken(ctx)
   183→}
   184→
   185→// type serverStreamingRetryingStream is the implementation of grpc.ClientStream that acts as a
   186→// proxy to the underlying call. If any of the RecvMsg() calls fail, it will try to reestablish
   187→// a new ClientStream according to the retry policy.
   188→type serverStreamingRetryingStream struct {
   189→	grpc.ClientStream
   190→	client        *Client
   191→	bufferedSends []any // single message that the client can sen
   192→	receivedGood  bool  // indicates whether any prior receives were successful
   193→	wasClosedSend bool  // indicates that CloseSend was closed
   194→	ctx           context.Context
   195→	callOpts      *options
   196→	streamerCall  func(ctx context.Context) (grpc.ClientStream, error)
   197→	mu            sync.RWMutex
   198→}
   199→
   200→func (s *serverStreamingRetryingStream) setStream(clientStream grpc.ClientStream) {
   201→	s.mu.Lock()
   202→	s.ClientStream = clientStream
   203→	s.mu.Unlock()
   204→}
   205→
   206→func (s *serverStreamingRetryingStream) getStream() grpc.ClientStream {
   207→	s.mu.RLock()
   208→	defer s.mu.RUnlock()
   209→	return s.ClientStream
   210→}
   211→
   212→func (s *serverStreamingRetryingStream) SendMsg(m any) error {
   213→	s.mu.Lock()
   214→	s.bufferedSends = append(s.bufferedSends, m)
   215→	s.mu.Unlock()
   216→	return s.getStream().SendMsg(m)
   217→}
   218→
   219→func (s *serverStreamingRetryingStream) CloseSend() error {
   220→	s.mu.Lock()
   221→	s.wasClosedSend = true
   222→	s.mu.Unlock()
   223→	return s.getStream().CloseSend()
   224→}
   225→
   226→func (s *serverStreamingRetryingStream) Header() (metadata.MD, error) {
   227→	return s.getStream().Header()
   228→}
   229→
   230→func (s *serverStreamingRetryingStream) Trailer() metadata.MD {
   231→	return s.getStream().Trailer()
   232→}
   233→
   234→func (s *serverStreamingRetryingStream) RecvMsg(m any) error {
   235→	attemptRetry, lastErr := s.receiveMsgAndIndicateRetry(m)
   236→	if !attemptRetry {
   237→		return lastErr // success or hard failure
   238→	}
   239→
   240→	// We start off from attempt 1, because zeroth was already made on normal SendMsg().
   241→	for attempt := uint(1); attempt < s.callOpts.max; attempt++ {
   242→		if err := waitRetryBackoff(s.ctx, attempt, s.callOpts); err != nil {
   243→			return err
   244→		}
   245→		newStream, err := s.reestablishStreamAndResendBuffer(s.ctx)
   246→		if err != nil {
   247→			s.client.GetLogger().Error("failed reestablishStreamAndResendBuffer", zap.Error(err))
   248→			return err // TODO(mwitkow): Maybe dial and transport errors should be retriable?
   249→		}
   250→		s.setStream(newStream)
   251→
   252→		s.client.GetLogger().Warn("retrying RecvMsg", zap.Error(lastErr))
   253→		attemptRetry, lastErr = s.receiveMsgAndIndicateRetry(m)
   254→		if !attemptRetry {
   255→			return lastErr
   256→		}
   257→	}
   258→	return lastErr
   259→}
   260→
   261→func (s *serverStreamingRetryingStream) receiveMsgAndIndicateRetry(m any) (bool, error) {
   262→	s.mu.RLock()
   263→	wasGood := s.receivedGood
   264→	s.mu.RUnlock()
   265→	err := s.getStream().RecvMsg(m)
   266→	if err == nil || errors.Is(err, io.EOF) {
   267→		s.mu.Lock()
   268→		s.receivedGood = true
   269→		s.mu.Unlock()
   270→		return false, err
   271→	} else if wasGood {
   272→		// previous RecvMsg in the stream succeeded, no retry logic should interfere
   273→		return false, err
   274→	}
   275→	if isContextError(err) {
   276→		if s.ctx.Err() != nil {
   277→			return false, err
   278→		}
   279→		// its the callCtx deadline or cancellation, in which case try again.
   280→		return true, err
   281→	}
   282→	if s.client.shouldRefreshToken(err, s.callOpts) {
   283→		gtErr := s.client.refreshToken(s.ctx)
   284→		if gtErr != nil {
   285→			s.client.GetLogger().Warn("retry failed to fetch new auth token", zap.Error(gtErr))
   286→			return false, err // return the original error for simplicity
   287→		}
   288→		return true, err
   289→	}
   290→	return isSafeRetry(s.client, err, s.callOpts), err
   291→}
   292→
   293→func (s *serverStreamingRetryingStream) reestablishStreamAndResendBuffer(callCtx context.Context) (grpc.ClientStream, error) {
   294→	s.mu.RLock()
   295→	bufferedSends := s.bufferedSends
   296→	s.mu.RUnlock()
   297→	newStream, err := s.streamerCall(callCtx)
   298→	if err != nil {
   299→		return nil, err
   300→	}
   301→	for _, msg := range bufferedSends {
   302→		if err := newStream.SendMsg(msg); err != nil {
   303→			return nil, err
   304→		}
   305→	}
   306→	if err := newStream.CloseSend(); err != nil {
   307→		return nil, err
   308→	}
   309→	return newStream, nil
   310→}
   311→
   312→func waitRetryBackoff(ctx context.Context, attempt uint, callOpts *options) error {
   313→	waitTime := time.Duration(0)
   314→	if attempt > 0 {
   315→		waitTime = callOpts.backoffFunc(attempt)
   316→	}
   317→	if waitTime > 0 {
   318→		timer := time.NewTimer(waitTime)
   319→		select {
   320→		case <-ctx.Done():
   321→			timer.Stop()
   322→			return contextErrToGRPCErr(ctx.Err())
   323→		case <-timer.C:
   324→		}
   325→	}
   326→	return nil
   327→}
   328→
   329→// isSafeRetry returns "true", if request is safe for retry with the given error.
   330→func isSafeRetry(c *Client, err error, callOpts *options) bool {
   331→	if isContextError(err) {
   332→		return false
   333→	}
   334→
   335→	// Situation when learner refuses RPC it is supposed to not serve is from the server
   336→	// perspective not retryable.
   337→	// But for backward-compatibility reasons we need  to support situation that
   338→	// customer provides mix of learners (not yet voters) and voters with an
   339→	// expectation to pick voter in the next attempt.
   340→	// TODO: Ideally client should be 'aware' which endpoint represents: leader/voter/learner with high probability.
   341→	if errors.Is(err, rpctypes.ErrGRPCNotSupportedForLearner) && len(c.Endpoints()) > 1 {
   342→		return true
   343→	}
   344→
   345→	switch callOpts.retryPolicy {
   346→	case repeatable:
   347→		return isSafeRetryImmutableRPC(err)
   348→	case nonRepeatable:
   349→		return isSafeRetryMutableRPC(err)
   350→	default:
   351→		c.GetLogger().Warn("unrecognized retry policy", zap.String("retryPolicy", callOpts.retryPolicy.String()))
   352→		return false
   353→	}
   354→}
   355→
   356→func isContextError(err error) bool {
   357→	return status.Code(err) == codes.DeadlineExceeded || status.Code(err) == codes.Canceled
   358→}
   359→
   360→func contextErrToGRPCErr(err error) error {
   361→	switch {
   362→	case errors.Is(err, context.DeadlineExceeded):
   363→		return status.Error(codes.DeadlineExceeded, err.Error())
   364→	case errors.Is(err, context.Canceled):
   365→		return status.Error(codes.Canceled, err.Error())
   366→	default:
   367→		return status.Error(codes.Unknown, err.Error())
   368→	}
   369→}
   370→
   371→var defaultOptions = &options{
   372→	retryPolicy: nonRepeatable,
   373→	max:         0, // disable
   374→	backoffFunc: backoffLinearWithJitter(50*time.Millisecond /*jitter*/, 0.10),
   375→	retryAuth:   true,
   376→}
   377→
   378→// backoffFunc denotes a family of functions that control the backoff duration between call retries.
   379→//
   380→// They are called with an identifier of the attempt, and should return a time the system client should
   381→// hold off for. If the time returned is longer than the `context.Context.Deadline` of the request
   382→// the deadline of the request takes precedence and the wait will be interrupted before proceeding
   383→// with the next iteration.
   384→type backoffFunc func(attempt uint) time.Duration
   385→
   386→// withRepeatablePolicy sets the repeatable policy of this call.
   387→func withRepeatablePolicy() retryOption {
   388→	return retryOption{applyFunc: func(o *options) {
   389→		o.retryPolicy = repeatable
   390→	}}
   391→}
   392→
   393→// withMax sets the maximum number of retries on this call, or this interceptor.
   394→func withMax(maxRetries uint) retryOption {
   395→	return retryOption{applyFunc: func(o *options) {
   396→		o.max = maxRetries
   397→	}}
   398→}
   399→
   400→// WithBackoff sets the `BackoffFunc` used to control time between retries.
   401→func withBackoff(bf backoffFunc) retryOption {
   402→	return retryOption{applyFunc: func(o *options) {
   403→		o.backoffFunc = bf
   404→	}}
   405→}
   406→
   407→type options struct {
   408→	retryPolicy retryPolicy
   409→	max         uint
   410→	backoffFunc backoffFunc
   411→	retryAuth   bool
   412→}
   413→
   414→// retryOption is a grpc.CallOption that is local to clientv3's retry interceptor.
   415→type retryOption struct {
   416→	grpc.EmptyCallOption // make sure we implement private after() and before() fields so we don't panic.
   417→	applyFunc            func(opt *options)
   418→}
   419→
   420→func reuseOrNewWithCallOptions(opt *options, retryOptions []retryOption) *options {
   421→	if len(retryOptions) == 0 {
   422→		return opt
   423→	}
   424→	optCopy := &options{}
   425→	*optCopy = *opt
   426→	for _, f := range retryOptions {
   427→		f.applyFunc(optCopy)
   428→	}
   429→	return optCopy
   430→}
   431→
   432→func filterCallOptions(callOptions []grpc.CallOption) (grpcOptions []grpc.CallOption, retryOptions []retryOption) {
   433→	for _, opt := range callOptions {
   434→		if co, ok := opt.(retryOption); ok {
   435→			retryOptions = append(retryOptions, co)
   436→		} else {
   437→			grpcOptions = append(grpcOptions, opt)
   438→		}
   439→	}
   440→	return grpcOptions, retryOptions
   441→}
   442→
   443→// BackoffLinearWithJitter waits a set period of time, allowing for jitter (fractional adjustment).
   444→//
   445→// For example waitBetween=1s and jitter=0.10 can generate waits between 900ms and 1100ms.
   446→func backoffLinearWithJitter(waitBetween time.Duration, jitterFraction float64) backoffFunc {
   447→	return func(attempt uint) time.Duration {
   448→		return jitterUp(waitBetween, jitterFraction)
   449→	}
   450→}
