    15→package clientv3
    16→
    17→import (
    18→	"context"
    19→	"errors"
    20→
    21→	"google.golang.org/grpc"
    22→	"google.golang.org/grpc/codes"
    23→	"google.golang.org/grpc/status"
    24→
    25→	pb "go.etcd.io/etcd/api/v3/etcdserverpb"
    26→	"go.etcd.io/etcd/api/v3/v3rpc/rpctypes"
    27→)
    28→
    29→type retryPolicy uint8
    30→
    31→const (
    32→	repeatable retryPolicy = iota
    33→	nonRepeatable
    34→)
    35→
    36→func (rp retryPolicy) String() string {
    37→	switch rp {
    38→	case repeatable:
    39→		return "repeatable"
    40→	case nonRepeatable:
    41→		return "nonRepeatable"
    42→	default:
    43→		return "UNKNOWN"
    44→	}
    45→}
    46→
    47→// isSafeRetryImmutableRPC returns "true" when an immutable request is safe for retry.
    48→//
    49→// immutable requests (e.g. Get) should be retried unless it's
    50→// an obvious server-side error (e.g. rpctypes.ErrRequestTooLarge).
    51→//
    52→// Returning "false" means retry should stop, since client cannot
    53→// handle itself even with retries.
    54→func isSafeRetryImmutableRPC(err error) bool {
    55→	eErr := rpctypes.Error(err)
    56→	var serverErr rpctypes.EtcdError
    57→	if errors.As(eErr, &serverErr) && serverErr.Code() != codes.Unavailable {
    58→		// interrupted by non-transient server-side or gRPC-side error
    59→		// client cannot handle itself (e.g. rpctypes.ErrCompacted)
    60→		return false
    61→	}
    62→	// only retry if unavailable
    63→	ev, ok := status.FromError(err)
    64→	if !ok {
    65→		// all errors from RPC is typed "grpc/status.(*statusError)"
    66→		// (ref. https://github.com/grpc/grpc-go/pull/1782)
    67→		//
    68→		// if the error type is not "grpc/status.(*statusError)",
    69→		// it could be from "Dial"
    70→		// TODO: do not retry for now
    71→		// ref. https://github.com/grpc/grpc-go/issues/1581
    72→		return false
    73→	}
    74→	return ev.Code() == codes.Unavailable
    75→}
    76→
    77→// isSafeRetryMutableRPC returns "true" when a mutable request is safe for retry.
    78→//
    79→// mutable requests (e.g. Put, Delete, Txn) should only be retried
    80→// when the status code is codes.Unavailable when initial connection
    81→// has not been established (no endpoint is up).
    82→//
    83→// Returning "false" means retry should stop, otherwise it violates
    84→// write-at-most-once semantics.
    85→func isSafeRetryMutableRPC(err error) bool {
    86→	if ev, ok := status.FromError(err); ok && ev.Code() != codes.Unavailable {
    87→		// not safe for mutable RPCs
    88→		// e.g. interrupted by non-transient error that client cannot handle itself,
    89→		// or transient error while the connection has already been established
    90→		return false
    91→	}
    92→	desc := rpctypes.ErrorDesc(err)
    93→	return desc == "there is no address available" || desc == "there is no connection available"
    94→}
