    96→type retryKVClient struct {
    97→	kc pb.KVClient
    98→}
    99→
   100→// RetryKVClient implements a KVClient.
   101→func RetryKVClient(c *Client) pb.KVClient {
   102→	return &retryKVClient{
   103→		kc: pb.NewKVClient(c.conn),
   104→	}
   105→}
