		callOpts: defaultCallOpts,
	}

	var err error
	var lg *zap.Logger
	if cfg.Logger != nil {
		lg = cfg.Logger
	} else if cfg.LogConfig != nil {
		lg, err = cfg.LogConfig.Build()
	} else {
		lg, err = logutil.CreateDefaultZapLogger(ClientLogLevel())
		if lg != nil {
			lg = lg.Named("etcd-client")
		}
	}
	if err != nil {
		return nil, err
	}
	client.lg.Store(lg)

